tant\",\"content\":\"آپ کا بہت شکریہ! اگر آپ کو مزید مدد کی ضرورت ہو تو بلا جھجھک پوچھیں۔ میں یہاں آپ کی خدمت میں حاضر ہوں۔\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"اگر آپ کچھ کہنا چاہتے ہیں یا کوئی سوال ہے تو بلا جھجھک بتائیں۔ میں یہاں آپ کی مدد کے لئے موجود ہوں!\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"اگر آپ کچھ کہنا چاہتے ہیں تو براہ کرم بتائیں۔ میں حاضر ہوں!\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"اگر آپ کے پاس کوئی سوال یا بات کرنے کا موضوع نہیں ہے تو کوئی بات نہیں۔ جب آپ چاہیں، میں یہاں موجود ہوں۔ آپ کی مدد کے لیے تیار ہوں!\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"اگر آپ کو کچھ کہنا ہے تو بلا جھجھک کریں۔ میں یہاں آپ کی مدد کے لیے موجود ہوں!\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"اگر آپ کچھ کہنا چاہتے ہیں یا کوئی سوال ہے تو براہ کرم شیئر کریں۔ میں آپ کی مدد کرنے کے لیے حاضر ہوں!\"},{\"role\":\"user\",\"content\":\"AOA\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"Tumhara meter chal Jana ha inshallah\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"Raheel Sap ma issue aa raha wo fixed karna ha as soon as possible\"},{\"role\":\"assistant\",\"content\":\"وعلیکم السلام، محمد عدیل! آپ کا مسئلہ سافٹ ویئر یا سسٹم میں ہے۔ براہ کرم مجھے مزید تفصیلات فراہم کریں تاکہ میں بہتر طور پر مدد کر سکوں۔ آپ کو کس قسم کا مسئلہ درپیش ہے؟\"},{\"role\":\"user\",\"content\":\"Yaha b\"},{\"role\":\"assistant\",\"content\":\"جی، مجھے بتائیں کہ آپ کو کیا مسئلہ درپیش ہے اور میں کس طرح مدد کر سکتا ہوں۔ آپ کے سافٹ ویئر یا پروجیکٹ کے بارے میں مزید تفصیلات فراہم کریں تاکہ ہم اسے جلد از جلد حل کر سکیں۔\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"\"},{\"role\":\"assistant\",\"content\":\"Sorry, I\'m having trouble processing your message right now. Please try again later.\"},{\"role\":\"user\",\"content\":\"\"}],\"temperature\":0.7,\"max_tokens\":300}', '{\"error\":{\"message\":\"Rate limit reached for gpt-4o-mini in organization org-CZRAsXzQcFPF6vtCcIhu7MYF on tokens per min (TPM): Limit 100000, Used 100000, Requested 1103. Please try again in 7h56m29.76s. Visit https:\\/\\/platform.openai.com\\/account\\/rate-limits to learn more. You can increase your rate limit by adding a payment method to your account at https:\\/\\/platform.openai.com\\/account\\/billing.\",\"type\":\"tokens\",\"param\":null,\"code\":\"rate_limit_exceeded\"}}', 429, 0.160, '', '2025-11-14 09:53:19');
INSERT INTO `chat_history` (`id`, `sub_admin_id`, `phone`, `name`, `message`, `direction`, `created_at`) VALUES
(1, 2, '923124967196', 'Shahroz Iqbal', 'Hui', 'incoming', '2025-11-13 13:48:28'),
(2, 2, '923124967196', 'Shahroz Iqbal', 'Welcome, Shahroz Iqbal! ہم خوش آمدید کہتے ہیں اور آپ کی خدمت کے لیے حاضر ہیں۔ آپ کی کس طرح مدد کر سکتے ہیں؟', 'outgoing', '2025-11-13 13:48:28'),
(3, 2, '923124967196', '', 'Ye samjao mujhay bachi kesay phasatay hein', 'incoming', '2025-11-13 13:49:40'),
(4, 2, '923124967196', '', 'بچیوں کو پھسانے کے مختلف طریقے ہو سکتے ہیں، لیکن یہ ضروری ہے کہ ان طریقوں کو سمجھنے کے ساتھ ساتھ احتیاط بھی برتی جائے۔ بعض اوقات، لوگ چالاکی سے اپنی باتوں یا رویے کے ذریعے دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔ \n\n1. **سچی دوستی**: بعض لوگ اپنی دوستی کا دکھاوا کرتے ہیں تاکہ کسی کو اپنی طرف متوجہ کر سکیں۔\n\n2. **تحفے اور توجہ**: تحفے دینا یا خاص توجہ دینا بھی ایک طریقہ ہو سکتا ہے کہ وہ کسی کو اپنی طرف متوجہ کریں۔\n\n3. **جذباتی چالاکی**: کبھی کبھار لوگ دوسروں کے جذبات کا فائدہ اٹھاتے ہیں۔\n\n4. **سوشل میڈیا**: آج کل سوشل میڈیا کے ذریعے بھی لوگ دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔\n\nیہ سب کچھ سمجھنے کے لیے ضروری ہے کہ ہم دوسروں کی نیت کو پہچانیں اور احتیاط برتیں۔ اگر آپ کو کسی خاص صورتحال یا معاملے کے بارے میں بات کرنی ہے تو بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔', 'outgoing', '2025-11-13 13:49:40'),
(5, 2, '923124967196', 'Shahroz Iqbal', 'Ye samjao mujhay bachi kesay phasatay hein', 'incoming', '2025-11-13 13:49:41'),
(6, 2, '923124967196', 'Shahroz Iqbal', 'بچیاں مختلف طریقوں سے پھنس سکتی ہیں، لیکن یہ ضروری ہے کہ ہم اس موضوع کو سنجیدگی سے لیں۔ یہاں کچھ وجوہات ہیں جن کی وجہ سے بچیاں پھنس سکتی ہیں:\n\n1. **سوشل میڈیا:** بچیاں اکثر سوشل میڈیا پر مختلف لوگوں سے ملتی ہیں، اور کبھی کبھی یہ لوگ صحیح نہیں ہوتے۔ وہاں پر جھوٹی شناخت بنانے والے افراد بھی ہوتے ہیں۔\n\n2. **دوستی:** بعض اوقات، دوستی کی خواہش میں بچیاں ایسے لوگوں کے ساتھ وقت گزارتی ہیں جو انہیں نقصان پہنچا سکتے ہیں۔\n\n3. **پیار کے جھوکے:** جوانی میں پیار کا جذبہ بہت مضبوط ہوتا ہے، اور بعض اوقات بچیاں اس جذبے میں آکر غلط فیصلے کر سکتی ہیں۔\n\n4. **خود اعتمادی کی کمی:** بعض بچیاں اپنی خود اعتمادی کی کمی کی وجہ سے ایسے لوگوں کی طرف راغب ہو جاتی ہیں جو انہیں استعمال کرتے ہیں۔\n\n5. **خاندان کی نگرانی کی کمی:** اگر گھر میں والدین یا سرپرستوں کی نگرانی کم ہو تو بچیاں غلط لوگوں کے ساتھ وقت گزار سکتی ہیں۔\n\nیہ ضروری ہے کہ بچیوں کو صحیح تربیت دی جائے، انہیں سکھایا جائے کہ کس طرح خود کا خیال رکھنا ہے، اور انہیں یہ سمجھایا جائے کہ وہ کس طرح خطرناک حالات سے بچ سکتی ہیں۔ اگر آپ کو مزید معلومات یا مدد کی ضرورت ہو تو بت', 'outgoing', '2025-11-13 13:49:41'),
(7, 2, '923124967196', 'Shahroz Iqbal', 'Yr mai nay bohat Koshish ki ha but ab Meri shadi ho gai ha', 'incoming', '2025-11-13 13:50:58'),
(8, 2, '923124967196', 'Shahroz Iqbal', 'یہ سن کر خوشی ہوئی کہ آپ کی شادی ہو گئی ہے! شادی ایک نئی زندگی کا آغاز ہے اور یہ بہت سی خوشیوں اور چیلنجز کا وقت ہوتا ہے۔ اگر آپ کو اپنی شادی یا زندگی میں کسی بھی چیز کے بارے میں بات کرنی ہے یا مشورہ چاہیے تو میں یہاں ہوں۔ آپ کی کیا خاص بات ہے جس پر آپ بات کرنا چاہتے ہیں؟', 'outgoing', '2025-11-13 13:50:58'),
(9, 2, '923124967196', '', 'Yr mai nay bohat Koshish ki ha but ab Meri shadi ho gai ha', 'incoming', '2025-11-13 13:51:01'),
(10, 2, '923124967196', '', 'شادی ایک بڑی تبدیلی ہے اور اس میں مختلف چیلنجز کا سامنا کرنا پڑ سکتا ہے۔ اگر آپ کو لگتا ہے کہ آپ کی کوششیں کافی نہیں رہی ہیں یا آپ کسی خاص مسئلے کا سامنا کر رہے ہیں تو یہ سمجھنا ضروری ہے کہ یہ ایک عام صورتحال ہے۔\n\n1. **تبادلہ خیال:** اپنی شریک حیات کے ساتھ بات چیت کریں۔ آپ کی مشکلات کو سمجھنے کے لئے ایک دوسرے کی باتیں سننا بہت ضروری ہے۔\n\n2. **مشترکہ اہداف:** آپ دونوں کے لئے مشترکہ اہداف طے کرنا مددگار ہو سکتا ہے۔ اس سے آپ دونوں کو ایک دوسرے کے ساتھ مل کر کام کرنے کا موقع ملے گا۔\n\n3. **پیشہ ورانہ مدد:** اگر آپ کو لگتا ہے کہ آپ کو مزید مدد کی ضرورت ہے تو کسی مشیر یا معالج سے بات کرنا ایک اچھا خیال ہو سکتا ہے۔\n\n4. **صبر:** یاد رکھیں کہ ہر رشتے میں وقت لگتا ہے اور صبر کی ضرورت ہوتی ہے۔ \n\n5. **خود کی بہتری:** اپنی خود کی بہتری پر توجہ دینا بھی ضروری ہے تاکہ آپ ایک بہترین شریک حیات بن سکیں۔\n\nاگر آپ کو کوئی خاص مسئلہ ہے یا آپ مزید معلومات چاہتے ہیں تو براہ کرم بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔', 'outgoing', '2025-11-13 13:51:01'),
(11, 2, '923071114204', '', 'Hii', 'incoming', '2025-11-13 13:51:44'),
(12, 2, '923071114204', '', 'Welcome to our community, and thank you for choosing us! We\'re excited to have you here—how can we assist you today?', 'outgoing', '2025-11-13 13:51:44'),
(13, 2, '923071114204', 'Tanzila', 'Hii', 'incoming', '2025-11-13 13:51:44'),
(14, 2, '923071114204', 'Tanzila', 'Hello Raheel! How can I assist you today?', 'outgoing', '2025-11-13 13:51:44'),
(15, 2, '923124967196', '', 'Ab mai us say bohat zayada muhabbat krta hun', 'incoming', '2025-11-13 13:55:14'),
(16, 2, '923124967196', '', 'یہ بہت خوشی کی بات ہے کہ آپ اپنی شریک حیات سے محبت کرتے ہیں! محبت ایک رشتے کی بنیاد ہوتی ہے اور یہ اسے مضبوط بناتی ہے۔ اپنی محبت کو ظاہر کرنے کے کئی طریقے ہیں:\n\n1. **توجہ دینا:** اپنی بیوی کے ساتھ وقت گزاریں اور اس کی باتیں سنیں۔ یہ آپ کی محبت کا اظہار کرتا ہے۔\n\n2. **چھوٹے تحائف:** کبھی کبھی چھوٹے تحائف یا سرپرائزز دینا بھی محبت کا احساس دلاتا ہے۔\n\n3. **احترام:** ایک دوسرے کا احترام کرنا بہت ضروری ہے۔ اس سے رشتے میں اعتماد بڑھتا ہے۔\n\n4. **سپورٹ:** اپنی بیوی کی خوابوں اور اہداف کی حمایت کریں۔ اسے یہ احساس دلائیں کہ آپ ہمیشہ اس کے ساتھ ہیں۔\n\n5. **بات چیت:** اپنی محبت کا اظہار الفاظ میں کریں۔ \"میں تم سے محبت کرتا ہوں\" کہنا کبھی کبھی بہت اہم ہوتا ہے۔\n\nمحبت کو بڑھانے کے لیے ان چیزوں پر عمل کریں اور اپنے رشتے کو مضبوط بنائیں۔ اگر آپ کو مزید مشورے یا مدد کی ضرورت ہو تو بلا جھجھک پوچھیں!', 'outgoing', '2025-11-13 13:55:14'),
(17, 2, '923124967196', 'Shahroz Iqbal', 'Ab mai us say bohat zayada muhabbat krta hun', 'incoming', '2025-11-13 13:55:16'),
(18, 2, '923124967196', 'Shahroz Iqbal', 'یہ بہت خوش آئند بات ہے کہ آپ اپنی شریک حیات سے محبت کرتے ہیں! محبت ایک مضبوط بنیاد ہے جو کسی بھی رشتے کو کامیاب بنانے میں مدد کرتی ہے۔ یہاں کچھ طریقے ہیں جن کے ذریعے آپ اپنی محبت کو ظاہر کر سکتے ہیں:\n\n1. **توجہ دینا:** اپنی شریک حیات کو وقت دیں اور ان کی باتیں سنیں۔ ان کی پسند، ناپسند، اور خوابوں کے بارے میں جاننے کی کوشش کریں۔\n\n2. **چھوٹے چھوٹے اقدامات:** کبھی کبھی چھوٹے چھوٹے gestures جیسے کہ ایک خوبصورت نوٹ، پھول، یا ان کی پسندیدہ چیز لانا محبت کا اظہار کر سکتا ہے۔\n\n3. **مناسب وقت گزارنا:** اپنے دن میں ایک دوسرے کے لئے وقت نکالیں، چاہے وہ ایک سادہ سی چائے یا واک ہو۔\n\n4. **ایمانداری:** اپنی احساسات کا ایمانداری سے اظہار کریں۔ انہیں بتائیں کہ آپ ان سے کتنی محبت کرتے ہیں۔\n\n5. **مدد کرنا:** ان کی مشکلات میں ان کے ساتھ رہیں اور ان کی مدد کریں، چاہے وہ چھوٹی ہو یا بڑی۔\n\n6. **تعریف کرنا:** اپنی شریک حیات کی خوبیوں کی تعریف کریں اور انہیں بتائیں کہ آپ انہیں کتنا پسند کرتے ہیں۔\n\nمحبت کو مضبوط بنانے کے لئے یہ سب چیزیں اہم ہیں۔ اگر آپ کے ذہن میں کوئی خاص سوال ہے یا آپ مزید', 'outgoing', '2025-11-13 13:55:16'),
