INSERT INTO `message_logs` (`id`, `sub_admin_id`, `phone`, `name`, `message`, `type`, `received_at`) VALUES
(1, 2, '923124967196', 'Shahroz Iqbal', 'Welcome, Shahroz Iqbal! ہم خوش آمدید کہتے ہیں اور آپ کی خدمت کے لیے حاضر ہیں۔ آپ کی کس طرح مدد کر سکتے ہیں؟ (Queued)', 'sent', '2025-11-13 13:48:28'),
(2, 2, '923124967196', 'Shahroz Iqbal', 'Hui', 'received', '2025-11-13 13:48:28'),
(3, 2, '923124967196', '', 'بچیوں کو پھسانے کے مختلف طریقے ہو سکتے ہیں، لیکن یہ ضروری ہے کہ ان طریقوں کو سمجھنے کے ساتھ ساتھ احتیاط بھی برتی جائے۔ بعض اوقات، لوگ چالاکی سے اپنی باتوں یا رویے کے ذریعے دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔ \n\n1. **سچی دوستی**: بعض لوگ اپنی دوستی کا دکھاوا کرتے ہیں تاکہ کسی کو اپنی طرف متوجہ کر سکیں۔\n\n2. **تحفے اور توجہ**: تحفے دینا یا خاص توجہ دینا بھی ایک طریقہ ہو سکتا ہے کہ وہ کسی کو اپنی طرف متوجہ کریں۔\n\n3. **جذباتی چالاکی**: کبھی کبھار لوگ دوسروں کے جذبات کا فائدہ اٹھاتے ہیں۔\n\n4. **سوشل میڈیا**: آج کل سوشل میڈیا کے ذریعے بھی لوگ دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔\n\nیہ سب کچھ سمجھنے کے لیے ضروری ہے کہ ہم دوسروں کی نیت کو پہچانیں اور احتیاط برتیں۔ اگر آپ کو کسی خاص صورتحال یا معاملے کے بارے میں بات کرنی ہے تو بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔ (Queued)', 'sent', '2025-11-13 13:49:40'),
(4, 2, '923124967196', '', 'Ye samjao mujhay bachi kesay phasatay hein', 'received', '2025-11-13 13:49:40'),
(5, 2, '923124967196', 'Shahroz Iqbal', 'بچیاں مختلف طریقوں سے پھنس سکتی ہیں، لیکن یہ ضروری ہے کہ ہم اس موضوع کو سنجیدگی سے لیں۔ یہاں کچھ وجوہات ہیں جن کی وجہ سے بچیاں پھنس سکتی ہیں:\n\n1. **سوشل میڈیا:** بچیاں اکثر سوشل میڈیا پر مختلف لوگوں سے ملتی ہیں، اور کبھی کبھی یہ لوگ صحیح نہیں ہوتے۔ وہاں پر جھوٹی شناخت بنانے والے افراد بھی ہوتے ہیں۔\n\n2. **دوستی:** بعض اوقات، دوستی کی خواہش میں بچیاں ایسے لوگوں کے ساتھ وقت گزارتی ہیں جو انہیں نقصان پہنچا سکتے ہیں۔\n\n3. **پیار کے جھوکے:** جوانی میں پیار کا جذبہ بہت مضبوط ہوتا ہے، اور بعض اوقات بچیاں اس جذبے میں آکر غلط فیصلے کر سکتی ہیں۔\n\n4. **خود اعتمادی کی کمی:** بعض بچیاں اپنی خود اعتمادی کی کمی کی وجہ سے ایسے لوگوں کی طرف راغب ہو جاتی ہیں جو انہیں استعمال کرتے ہیں۔\n\n5. **خاندان کی نگرانی کی کمی:** اگر گھر میں والدین یا سرپرستوں کی نگرانی کم ہو تو بچیاں غلط لوگوں کے ساتھ وقت گزار سکتی ہیں۔\n\nیہ ضروری ہے کہ بچیوں کو صحیح تربیت دی جائے، انہیں سکھایا جائے کہ کس طرح خود کا خیال رکھنا ہے، اور انہیں یہ سمجھایا جائے کہ وہ کس طرح خطرناک حالات سے بچ سکتی ہیں۔ اگر آپ کو مزید معلومات یا مدد کی ضرورت ہو تو بت (Queued)', 'sent', '2025-11-13 13:49:41'),
(6, 2, '923124967196', 'Shahroz Iqbal', 'Ye samjao mujhay bachi kesay phasatay hein', 'received', '2025-11-13 13:49:41'),
(7, 2, '923124967196', 'Shahroz Iqbal', 'یہ سن کر خوشی ہوئی کہ آپ کی شادی ہو گئی ہے! شادی ایک نئی زندگی کا آغاز ہے اور یہ بہت سی خوشیوں اور چیلنجز کا وقت ہوتا ہے۔ اگر آپ کو اپنی شادی یا زندگی میں کسی بھی چیز کے بارے میں بات کرنی ہے یا مشورہ چاہیے تو میں یہاں ہوں۔ آپ کی کیا خاص بات ہے جس پر آپ بات کرنا چاہتے ہیں؟ (Queued)', 'sent', '2025-11-13 13:50:58'),
(8, 2, '923124967196', 'Shahroz Iqbal', 'Yr mai nay bohat Koshish ki ha but ab Meri shadi ho gai ha', 'received', '2025-11-13 13:50:58'),
(9, 2, '923124967196', '', 'شادی ایک بڑی تبدیلی ہے اور اس میں مختلف چیلنجز کا سامنا کرنا پڑ سکتا ہے۔ اگر آپ کو لگتا ہے کہ آپ کی کوششیں کافی نہیں رہی ہیں یا آپ کسی خاص مسئلے کا سامنا کر رہے ہیں تو یہ سمجھنا ضروری ہے کہ یہ ایک عام صورتحال ہے۔\n\n1. **تبادلہ خیال:** اپنی شریک حیات کے ساتھ بات چیت کریں۔ آپ کی مشکلات کو سمجھنے کے لئے ایک دوسرے کی باتیں سننا بہت ضروری ہے۔\n\n2. **مشترکہ اہداف:** آپ دونوں کے لئے مشترکہ اہداف طے کرنا مددگار ہو سکتا ہے۔ اس سے آپ دونوں کو ایک دوسرے کے ساتھ مل کر کام کرنے کا موقع ملے گا۔\n\n3. **پیشہ ورانہ مدد:** اگر آپ کو لگتا ہے کہ آپ کو مزید مدد کی ضرورت ہے تو کسی مشیر یا معالج سے بات کرنا ایک اچھا خیال ہو سکتا ہے۔\n\n4. **صبر:** یاد رکھیں کہ ہر رشتے میں وقت لگتا ہے اور صبر کی ضرورت ہوتی ہے۔ \n\n5. **خود کی بہتری:** اپنی خود کی بہتری پر توجہ دینا بھی ضروری ہے تاکہ آپ ایک بہترین شریک حیات بن سکیں۔\n\nاگر آپ کو کوئی خاص مسئلہ ہے یا آپ مزید معلومات چاہتے ہیں تو براہ کرم بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔ (Queued)', 'sent', '2025-11-13 13:51:01'),
