(1, 2, 'ee21cc4642e8bff06f1e5d721a2cfc9e5913196001eccb232f07e55b0c182f1c', 'a5fcd144482c63078ea5f8fe30a4fa770e844618fe044f87', 'chatgpt', '', 'sk-proj-REDACTED', '06a7295eb183562d80c3be8bcb583bb09b531a0fc2126d0840792683f5fe6bff', 'ap chatbot product kii sale agent ho ', '1. Persona & Tone (Aapki Pehchan)\r\nAapka naam aik professional sales expert ka hai. Aapka lehja Friendly,\r\nProfessional aur Helpful hona chahiye.\r\nLanguage: Customer jis zuban mein baat kare (Roman Urdu, Hinglish ya\r\nEnglish), aapne usay usi mein jawab dena hai.\r\n\"Assalam-o-Alaikum! Main [Store Name] se baat kar raha hoon. Main aapki kaise behtreen madad\r\nkar sakta hoon?\"\r\n\r\n2. Product Features (Key Selling Points)\r\nJab bhi customer product ke baare mein pooche, in features ko highlight karein:\r\nPremium Quality: Hum quality par compromise nahi karte.\r\nBest Price: Market se behtar qeemat aur value.\r\nFast Support: Sale ke baad bhi hum har waqt hazir hain.\r\nSpecial Offer: Agar aap aaj order karte hain, toh [Specific Discount] mil\r\nsakta hai.\r\n\r\n3. Sales Strategy (Closing the Deal)\r\nSirf sawal ka jawab nahi dena, sale ko finalize karna hai:\r\nStep 1 (Need): Pehle puche ke customer ko kis tarah ki product chahiye.\r\nExpert Sales & Support Training for Digital Products\r\n\r\n•\r\n•\r\n•\r\n•\r\n\r\nStep 2 (Benefit): Usay batayein ke ye product uski mushkil kaise hal karegi.\r\nStep 3 (Urgency): Batayein ke stock limited hai ya offer khatam honay wali hai.\r\nStep 4 (CTA): Seedha puche, \"Kya main aapka order confirm kar doon?\"\r\n\r\n4. Handling Objections (Etirazat ka Jawab)\r\n\r\nCustomer Kya\r\nKehta Hai?\r\n\r\nAI Agent ka Jawab\r\n\r\n\"Price bohat zyada\r\nhai.\"\r\n\r\n\"Sir, hamari quality aur warranty market se alag hai. Ye cheez lene ke\r\nbaad aapko pachtawa nahi hoga.\"\r\n\r\n\"Kya ye original\r\nhai?\"\r\n\r\n\"Ji bilkul! Hum 100% original product deliver karte hain aur hamari\r\ncustomer ratings iska saboot hain.\"\r\n\r\n\"Mujhe baad mein\r\nlena hai.\"\r\n\r\n\"Theek hai sir, lekin abhi 20% discount chal raha hai jo aaj raat khatam\r\nho jayega. Kya main aapke liye aik unit reserve kar loon?\"\r\n\r\n5. Order Confirmation Process\r\n\r\nJab customer maan jaye, toh foran ye details maangein:\r\nMukammal Naam (Full Name)\r\nMobile Number (Active)\r\nMukammal Address (Ghar ka pata aur shehar)\r\nPreferred Payment Method (COD ya Online)', '128470,128473,879009', 60, 0, 'apka naam meerab ho apki date of birth 25/07/1993 ha ', '2025-11-13 09:01:08', '2026-04-15 16:03:55'),
(2, 1, '15ee825e2ea2ec948840445234d7b4f8274efc1f174079d70bf4bc7159f06b98', 'a6f3a8f41e7454b693cbace976e8977197698fa446188b3f', 'gemini', '', '', '', '', '', '', 60, 0, NULL, '2026-04-11 16:27:51', '2026-04-17 02:35:44');
INSERT INTO `whatsapp_messages` (`id`, `sub_admin_id`, `phone`, `name`, `message`, `request_payload`, `response_data`, `http_code`, `success`, `error`, `created_at`) VALUES
(1, 2, '923124967196', 'Shahroz Iqbal', 'Welcome, Shahroz Iqbal! ہم خوش آمدید کہتے ہیں اور آپ کی خدمت کے لیے حاضر ہیں۔ آپ کی کس طرح مدد کر سکتے ہیں؟', '{\"to\":\"+923124967196\",\"text\":\"Welcome, Shahroz Iqbal! ہم خوش آمدید کہتے ہیں اور آپ کی خدمت کے لیے حاضر ہیں۔ آپ کی کس طرح مدد کر سکتے ہیں؟\"}', '{\"success\":true,\"data\":{\"msgId\":11106183,\"jid\":\"+923124967196\",\"status\":\"in_progress\"}}', 200, 1, '', '2025-11-13 13:48:53'),
(2, 2, '923124967196', '', 'بچیوں کو پھسانے کے مختلف طریقے ہو سکتے ہیں، لیکن یہ ضروری ہے کہ ان طریقوں کو سمجھنے کے ساتھ ساتھ احتیاط بھی برتی جائے۔ بعض اوقات، لوگ چالاکی سے اپنی باتوں یا رویے کے ذریعے دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔ \n\n1. **سچی دوستی**: بعض لوگ اپنی دوستی کا دکھاوا کرتے ہیں تاکہ کسی کو اپنی طرف متوجہ کر سکیں۔\n\n2. **تحفے اور توجہ**: تحفے دینا یا خاص توجہ دینا بھی ایک طریقہ ہو سکتا ہے کہ وہ کسی کو اپنی طرف متوجہ کریں۔\n\n3. **جذباتی چالاکی**: کبھی کبھار لوگ دوسروں کے جذبات کا فائدہ اٹھاتے ہیں۔\n\n4. **سوشل میڈیا**: آج کل سوشل میڈیا کے ذریعے بھی لوگ دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔\n\nیہ سب کچھ سمجھنے کے لیے ضروری ہے کہ ہم دوسروں کی نیت کو پہچانیں اور احتیاط برتیں۔ اگر آپ کو کسی خاص صورتحال یا معاملے کے بارے میں بات کرنی ہے تو بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔', '{\"to\":\"+923124967196\",\"text\":\"بچیوں کو پھسانے کے مختلف طریقے ہو سکتے ہیں، لیکن یہ ضروری ہے کہ ان طریقوں کو سمجھنے کے ساتھ ساتھ احتیاط بھی برتی جائے۔ بعض اوقات، لوگ چالاکی سے اپنی باتوں یا رویے کے ذریعے دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔ \\n\\n1. **سچی دوستی**: بعض لوگ اپنی دوستی کا دکھاوا کرتے ہیں تاکہ کسی کو اپنی طرف متوجہ کر سکیں۔\\n\\n2. **تحفے اور توجہ**: تحفے دینا یا خاص توجہ دینا بھی ایک طریقہ ہو سکتا ہے کہ وہ کسی کو اپنی طرف متوجہ کریں۔\\n\\n3. **جذباتی چالاکی**: کبھی کبھار لوگ دوسروں کے جذبات کا فائدہ اٹھاتے ہیں۔\\n\\n4. **سوشل میڈیا**: آج کل سوشل میڈیا کے ذریعے بھی لوگ دوسروں کو متاثر کرنے کی کوشش کرتے ہیں۔\\n\\nیہ سب کچھ سمجھنے کے لیے ضروری ہے کہ ہم دوسروں کی نیت کو پہچانیں اور احتیاط برتیں۔ اگر آپ کو کسی خاص صورتحال یا معاملے کے بارے میں بات کرنی ہے تو بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔\"}', '{\"success\":true,\"data\":{\"msgId\":11106430,\"jid\":\"+923124967196\",\"status\":\"in_progress\"}}', 200, 1, '', '2025-11-13 13:50:05'),
(3, 2, '923124967196', 'Shahroz Iqbal', 'بچیاں مختلف طریقوں سے پھنس سکتی ہیں، لیکن یہ ضروری ہے کہ ہم اس موضوع کو سنجیدگی سے لیں۔ یہاں کچھ وجوہات ہیں جن کی وجہ سے بچیاں پھنس سکتی ہیں:\n\n1. **سوشل میڈیا:** بچیاں اکثر سوشل میڈیا پر مختلف لوگوں سے ملتی ہیں، اور کبھی کبھی یہ لوگ صحیح نہیں ہوتے۔ وہاں پر جھوٹی شناخت بنانے والے افراد بھی ہوتے ہیں۔\n\n2. **دوستی:** بعض اوقات، دوستی کی خواہش میں بچیاں ایسے لوگوں کے ساتھ وقت گزارتی ہیں جو انہیں نقصان پہنچا سکتے ہیں۔\n\n3. **پیار کے جھوکے:** جوانی میں پیار کا جذبہ بہت مضبوط ہوتا ہے، اور بعض اوقات بچیاں اس جذبے میں آکر غلط فیصلے کر سکتی ہیں۔\n\n4. **خود اعتمادی کی کمی:** بعض بچیاں اپنی خود اعتمادی کی کمی کی وجہ سے ایسے لوگوں کی طرف راغب ہو جاتی ہیں جو انہیں استعمال کرتے ہیں۔\n\n5. **خاندان کی نگرانی کی کمی:** اگر گھر میں والدین یا سرپرستوں کی نگرانی کم ہو تو بچیاں غلط لوگوں کے ساتھ وقت گزار سکتی ہیں۔\n\nیہ ضروری ہے کہ بچیوں کو صحیح تربیت دی جائے، انہیں سکھایا جائے کہ کس طرح خود کا خیال رکھنا ہے، اور انہیں یہ سمجھایا جائے کہ وہ کس طرح خطرناک حالات سے بچ سکتی ہیں۔ اگر آپ کو مزید معلومات یا مدد کی ضرورت ہو تو بت', '{\"to\":\"+923124967196\",\"text\":\"بچیاں مختلف طریقوں سے پھنس سکتی ہیں، لیکن یہ ضروری ہے کہ ہم اس موضوع کو سنجیدگی سے لیں۔ یہاں کچھ وجوہات ہیں جن کی وجہ سے بچیاں پھنس سکتی ہیں:\\n\\n1. **سوشل میڈیا:** بچیاں اکثر سوشل میڈیا پر مختلف لوگوں سے ملتی ہیں، اور کبھی کبھی یہ لوگ صحیح نہیں ہوتے۔ وہاں پر جھوٹی شناخت بنانے والے افراد بھی ہوتے ہیں۔\\n\\n2. **دوستی:** بعض اوقات، دوستی کی خواہش میں بچیاں ایسے لوگوں کے ساتھ وقت گزارتی ہیں جو انہیں نقصان پہنچا سکتے ہیں۔\\n\\n3. **پیار کے جھوکے:** جوانی میں پیار کا جذبہ بہت مضبوط ہوتا ہے، اور بعض اوقات بچیاں اس جذبے میں آکر غلط فیصلے کر سکتی ہیں۔\\n\\n4. **خود اعتمادی کی کمی:** بعض بچیاں اپنی خود اعتمادی کی کمی کی وجہ سے ایسے لوگوں کی طرف راغب ہو جاتی ہیں جو انہیں استعمال کرتے ہیں۔\\n\\n5. **خاندان کی نگرانی کی کمی:** اگر گھر میں والدین یا سرپرستوں کی نگرانی کم ہو تو بچیاں غلط لوگوں کے ساتھ وقت گزار سکتی ہیں۔\\n\\nیہ ضروری ہے کہ بچیوں کو صحیح تربیت دی جائے، انہیں سکھایا جائے کہ کس طرح خود کا خیال رکھنا ہے، اور انہیں یہ سمجھایا جائے کہ وہ کس طرح خطرناک حالات سے بچ سکتی ہیں۔ اگر آپ کو مزید معلومات یا مدد کی ضرورت ہو تو بت\"}', '{\"message\":\"You are on a free trial. You can send 1 message every 1 minute.\",\"retry_after\":59,\"help\":\"Upgrade to a paid plan to increase your rate limit.\"}', 429, 0, '', '2025-11-13 13:50:06'),
(4, 2, '923124967196', 'Shahroz Iqbal', 'یہ سن کر خوشی ہوئی کہ آپ کی شادی ہو گئی ہے! شادی ایک نئی زندگی کا آغاز ہے اور یہ بہت سی خوشیوں اور چیلنجز کا وقت ہوتا ہے۔ اگر آپ کو اپنی شادی یا زندگی میں کسی بھی چیز کے بارے میں بات کرنی ہے یا مشورہ چاہیے تو میں یہاں ہوں۔ آپ کی کیا خاص بات ہے جس پر آپ بات کرنا چاہتے ہیں؟', '{\"to\":\"+923124967196\",\"text\":\"یہ سن کر خوشی ہوئی کہ آپ کی شادی ہو گئی ہے! شادی ایک نئی زندگی کا آغاز ہے اور یہ بہت سی خوشیوں اور چیلنجز کا وقت ہوتا ہے۔ اگر آپ کو اپنی شادی یا زندگی میں کسی بھی چیز کے بارے میں بات کرنی ہے یا مشورہ چاہیے تو میں یہاں ہوں۔ آپ کی کیا خاص بات ہے جس پر آپ بات کرنا چاہتے ہیں؟\"}', '{\"message\":\"You are on a free trial. You can send 1 message every 1 minute.\",\"retry_after\":4,\"help\":\"Upgrade to a paid plan to increase your rate limit.\"}', 429, 0, '', '2025-11-13 13:51:01'),
(5, 2, '923124967196', '', 'شادی ایک بڑی تبدیلی ہے اور اس میں مختلف چیلنجز کا سامنا کرنا پڑ سکتا ہے۔ اگر آپ کو لگتا ہے کہ آپ کی کوششیں کافی نہیں رہی ہیں یا آپ کسی خاص مسئلے کا سامنا کر رہے ہیں تو یہ سمجھنا ضروری ہے کہ یہ ایک عام صورتحال ہے۔\n\n1. **تبادلہ خیال:** اپنی شریک حیات کے ساتھ بات چیت کریں۔ آپ کی مشکلات کو سمجھنے کے لئے ایک دوسرے کی باتیں سننا بہت ضروری ہے۔\n\n2. **مشترکہ اہداف:** آپ دونوں کے لئے مشترکہ اہداف طے کرنا مددگار ہو سکتا ہے۔ اس سے آپ دونوں کو ایک دوسرے کے ساتھ مل کر کام کرنے کا موقع ملے گا۔\n\n3. **پیشہ ورانہ مدد:** اگر آپ کو لگتا ہے کہ آپ کو مزید مدد کی ضرورت ہے تو کسی مشیر یا معالج سے بات کرنا ایک اچھا خیال ہو سکتا ہے۔\n\n4. **صبر:** یاد رکھیں کہ ہر رشتے میں وقت لگتا ہے اور صبر کی ضرورت ہوتی ہے۔ \n\n5. **خود کی بہتری:** اپنی خود کی بہتری پر توجہ دینا بھی ضروری ہے تاکہ آپ ایک بہترین شریک حیات بن سکیں۔\n\nاگر آپ کو کوئی خاص مسئلہ ہے یا آپ مزید معلومات چاہتے ہیں تو براہ کرم بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔', '{\"to\":\"+923124967196\",\"text\":\"شادی ایک بڑی تبدیلی ہے اور اس میں مختلف چیلنجز کا سامنا کرنا پڑ سکتا ہے۔ اگر آپ کو لگتا ہے کہ آپ کی کوششیں کافی نہیں رہی ہیں یا آپ کسی خاص مسئلے کا سامنا کر رہے ہیں تو یہ سمجھنا ضروری ہے کہ یہ ایک عام صورتحال ہے۔\\n\\n1. **تبادلہ خیال:** اپنی شریک حیات کے ساتھ بات چیت کریں۔ آپ کی مشکلات کو سمجھنے کے لئے ایک دوسرے کی باتیں سننا بہت ضروری ہے۔\\n\\n2. **مشترکہ اہداف:** آپ دونوں کے لئے مشترکہ اہداف طے کرنا مددگار ہو سکتا ہے۔ اس سے آپ دونوں کو ایک دوسرے کے ساتھ مل کر کام کرنے کا موقع ملے گا۔\\n\\n3. **پیشہ ورانہ مدد:** اگر آپ کو لگتا ہے کہ آپ کو مزید مدد کی ضرورت ہے تو کسی مشیر یا معالج سے بات کرنا ایک اچھا خیال ہو سکتا ہے۔\\n\\n4. **صبر:** یاد رکھیں کہ ہر رشتے میں وقت لگتا ہے اور صبر کی ضرورت ہوتی ہے۔ \\n\\n5. **خود کی بہتری:** اپنی خود کی بہتری پر توجہ دینا بھی ضروری ہے تاکہ آپ ایک بہترین شریک حیات بن سکیں۔\\n\\nاگر آپ کو کوئی خاص مسئلہ ہے یا آپ مزید معلومات چاہتے ہیں تو براہ کرم بتائیں، میں آپ کی مدد کرنے کے لیے یہاں ہوں۔\"}', '{\"success\":true,\"data\":{\"msgId\":11106769,\"jid\":\"+923124967196\",\"status\":\"in_progress\"}}', 200, 1, '', '2025-11-13 13:52:01'),
